#include<bits/stdc++.h>
using namespace std;
struct num{
	int a,b;
}f[1005];
int n,s[1005];
string max_m="",str[1005];
bool cmp(num x,num y){
	return x.a*x.b<y.a*y.b;
}
int to_Int(string s){
	int as=0;
	for(int i=0;i<s.size();i++)as=as*10+s[i]-'0';
	return as;
}
string to_str(int x){
    string as="";
    while(x!=0){
        as=(char)(x%10+'0')+as;
        x/=10;
    }
    return as;
}
string cheng_fa(string x,int b){
	string Cans="";
	int xx[x.size()+30],st=1,ed=x.size();
	memset(xx,0,sizeof(xx));
	for(int i=0;i<ed;i++)xx[ed-i]=x[i]-'0';
	for(int i=st;i<=ed;i++)xx[i]*=b;
	for(int i=st;i<=ed;i++){
		xx[i+1]+=xx[i]/10;
		xx[i]=xx[i]%10;
	}
	while(xx[ed+1]!=0){
		ed++;
		xx[ed+1]+=xx[ed]/10;
		xx[ed]=xx[ed]%10;
	}
	for(int i=ed;i>=st;i--)Cans+=(char)(xx[i]+'0');
	return Cans;
}
string chu_fa(string s,int p){// return s/p
    string as="";
    int xx[s.size()+30],ans[s.size()+30],k=0,len,st=1,ed=s.size();
    for(int i=1;i<=(int)(s.size());i++)xx[i]=(int)(s[i-1]-'0');
    for(int i=1;i<=(int)(s.size());i++){
        k=k*10+xx[i];
        ans[++len]=k/p;
        k=k%p;
    }
    while(!ans[st])st++;
    for(int i=st;i<=ed;i++)as+=(char)(ans[i]+'0');
    if(as=="")as="0";
    return as;
}
string SUM(int ed){
	string Sans="";
	if(ed>=2)str[ed-1]=cheng_fa(str[ed-2],f[ed-1].a);
	Sans=chu_fa(str[ed-1],f[ed].b);
	return Sans;
}
string Max(string s1,string s2){
    if(s1=="")return s2;
    if(s1.size()==s2.size()){
        if(s1>s2)return s1;
        else return s2;
    }
    else{
        if(s1.size()>s2.size())return s1;
        else return s2;
    }
}
int main(){
	scanf("%d",&n);
	scanf("%d %d",&f[0].a,&f[0].b);
	s[0]=f[0].a;
	for(int i=1;i<=n;i++){
		scanf("%d %d",&f[i].a,&f[i].b);
		s[i]=s[i-1]*f[i].a;
	}
	sort(f+1,f+n+1,cmp);
	str[0]=to_str(f[0].a);
	for(int i=1;i<=n;i++){
        string now=SUM(i);
		max_m=Max(max_m,now);
	}
	cout<<max_m;
	return 0;
}
